internal class SqliterStatement(
  private val statement: Statement,
) : SqlPreparedStatement {
  override fun bindBytes(index: Int, bytes: ByteArray?) {
    statement.bindBlob(index + 1, bytes)
  }

  override fun bindLong(index: Int, long: Long?) {
    statement.bindLong(index + 1, long)
  }

  override fun bindDouble(index: Int, double: Double?) {
    statement.bindDouble(index + 1, double)
  }

  override fun bindString(index: Int, string: String?) {
    statement.bindString(index + 1, string)
  }

  override fun bindBoolean(index: Int, boolean: Boolean?) {
    statement.bindLong(
      index + 1,
      when (boolean) {
        null -> null
        true -> 1L
        false -> 0L
      },
    )
  }
}

internal fun cleanUp() {
    operationsSinceCleanUp = 0

    // Remove all the values whose references have been collected.
    val iterator = cache.values.iterator()
    while (iterator.hasNext()) {
        val list = iterator.next()

        if (list.size <= 1) {
            // Typically, the list will only contain 1 item. Handle this case in an optimal way here.
            if (list.firstOrNull()?.image?.get() == null) {
                iterator.remove()
            }
        } else {
            // Iterate over the list of values and delete individual entries that have been collected.
            list.removeIfIndices { it.image.get() == null }

            if (list.isEmpty()) {
                iterator.remove()
            }
        }
    }
}

fun tryAcquire(): Boolean {
    while (true) {
        // Get the current number of available permits.
        val p = _availablePermits.value
        // Is the number of available permits greater
        // than the maximal one because of an incorrect
        // `release()` call without a preceding `acquire()`?
        // Change it to `permits` and start from the beginning.
        if (p > permits) {
            coerceAvailablePermitsAtMaximum()
            continue
        }
        // Try to decrement the number of available
        // permits if it is greater than zero.
        if (p <= 0) return false
        if (_availablePermits.compareAndSet(p, p - 1)) return true
    }
}

private fun trySuspend(): Boolean {
    _decision.loop { decision ->
        when (decision) {
            UNDECIDED -> if (this._decision.compareAndSet(UNDECIDED, SUSPENDED)) return true
            RESUMED -> return false
            else -> error("Already suspended")
        }
    }
}

private fun tryResume(): Boolean {
    _decision.loop { decision ->
        when (decision) {
            UNDECIDED -> if (this._decision.compareAndSet(UNDECIDED, RESUMED)) return true
            SUSPENDED -> return false
            else -> error("Already resumed")
        }
    }
}

internal class ComposerWithPrettyPrint(
    writer: InternalJsonWriter,
    private val json: Json
) : Composer(writer) {
    private var level = 0

    override fun indent() {
        writingFirst = true
        level++
    }

    override fun unIndent() {
        level--
    }

    override fun nextItem() {
        writingFirst = false
        print("\n")
        repeat(level) { print(json.configuration.prettyPrintIndent) }
    }

    override fun nextItemIfNotFirst() {
        if (writingFirst) writingFirst = false
        else nextItem()
    }

    override fun space() {
        print(' ')
    }
}

internal fun SerialDescriptor.serializationNamesIndices(json: Json, strategy: JsonNamingStrategy): Array<String> =
    json.schemaCache.getOrPut(this, JsonSerializationNamesKey) {
        val trackingSet = mutableSetOf<String>()
        Array(elementsCount) { i ->
            val baseName = getElementName(i)
            val name = strategy.serialNameForJson(this, i, baseName)
            if (!trackingSet.add(name)) throw JsonEncodingException(
                "The transformed name '$name' for property $baseName already exists " +
                    "in ${this@serializationNamesIndices}",
                classSerialName = this@serializationNamesIndices.serialName,
            )
            name
        }
    }

private fun decodeMapIndex(): Int {
    var hasComma = false
    val decodingKey = currentIndex % 2 != 0
    if (decodingKey) {
        if (currentIndex != -1) {
            hasComma = lexer.tryConsumeComma()
        }
    } else {
        lexer.consumeNextToken(COLON)
    }

    return if (lexer.canConsumeValue()) {
        if (decodingKey) {
            if (currentIndex == -1) lexer.require(!hasComma) { "Unexpected leading comma" }
            else lexer.require(hasComma) { "Expected comma after the key-value pair" }
        }
        ++currentIndex
    } else {
        if (hasComma && !json.configuration.allowTrailingComma) lexer.invalidTrailingComma()
        CompositeDecoder.DECODE_DONE
    }
}

public object TrailingSlashRouteSelector : RouteSelector(), RoutePathComponent {

    override suspend fun evaluate(context: RoutingResolveContext, segmentIndex: Int): RouteSelectorEvaluation = when {
        context.call.ignoreTrailingSlash -> RouteSelectorEvaluation.Transparent
        context.segments.isEmpty() -> RouteSelectorEvaluation.Constant
        segmentIndex < context.segments.lastIndex -> RouteSelectorEvaluation.Transparent
        segmentIndex > context.segments.lastIndex -> RouteSelectorEvaluation.FailedPath
        context.segments[segmentIndex].isNotEmpty() -> RouteSelectorEvaluation.Transparent
        context.hasTrailingSlash -> RouteSelectorEvaluation.ConstantPath
        else -> RouteSelectorEvaluation.FailedPath
    }

    override fun toString(): String = "<slash>"
}

override fun call(invocation: Invocation): Any? {
        val stub = recorder.stubRepo.stubFor(invocation.self)
        stub.recordCall(invocation.copy(originalCall = { null }))
        try {
            val answer = stub.answer(invocation)
            log.debug { "Answering ${answer.toStr()} on $invocation" }
            return answer
        } catch (ex: Exception) {
            log.debug { "Throwing ${ex.toStr()} on $invocation" }
            throw ex
        }
    }

    override fun startStubbing() = recorder.factories.stubbingState(recorder)

override fun recordCall(invocation: Invocation) {
    val record =
        when {
            checkExcluded(invocation) -> {
                log.debug { "Call excluded: $invocation" }
                false
            }
            recordPrivateCalls -> true
            else -> !invocation.method.privateCall
        }

    if (record) {
        recordedCalls.add(invocation)

        InternalPlatform.synchronized(recordedCallsByMethod) {
            recordedCallsByMethod
                .getOrPut(invocation.method) { mutableListOf() }
                .add(invocation)
        }

        gatewayAccess.stubRepository.notifyCallRecorded(this)
    }
}

fun split(byteCount: Int): Segment {
  require(byteCount > 0 && byteCount <= limit - pos) { "byteCount out of range" }
  val prefix: Segment

  // We have two competing performance goals:
  //  - Avoid copying data. We accomplish this by sharing segments.
  //  - Avoid short shared segments. These are bad for performance because they are readonly and
  //    may lead to long chains of short segments.
  // To balance these goals we only share segments when the copy will be large.
  if (byteCount >= SHARE_MINIMUM) {
    prefix = sharedCopy()
  } else {
    prefix = SegmentPool.take()
    data.copyInto(prefix.data, startIndex = pos, endIndex = pos + byteCount)
  }

  prefix.limit = prefix.pos + byteCount
  pos += byteCount
  prev!!.push(prefix)
  return prefix
}

fun writeTo(sink: Segment, byteCount: Int) {
  check(sink.owner) { "only owner can write" }
  if (sink.limit + byteCount > SIZE) {
    // We can't fit byteCount bytes at the sink's current position. Shift sink first.
    if (sink.shared) throw IllegalArgumentException()
    if (sink.limit + byteCount - sink.pos > SIZE) throw IllegalArgumentException()
    sink.data.copyInto(sink.data, startIndex = sink.pos, endIndex = sink.limit)
    sink.limit -= sink.pos
    sink.pos = 0
  }

  data.copyInto(
    sink.data,
    destinationOffset = sink.limit,
    startIndex = pos,
    endIndex = pos + byteCount,
  )
  sink.limit += byteCount
  pos += byteCount
}

internal fun rangeEquals(
  segment: Segment,
  segmentPos: Int,
  bytes: ByteArray,
  bytesOffset: Int,
  bytesLimit: Int,
): Boolean {
  var segment = segment
  var segmentPos = segmentPos
  var segmentLimit = segment.limit
  var data = segment.data

  var i = bytesOffset
  while (i < bytesLimit) {
    if (segmentPos == segmentLimit) {
      segment = segment.next!!
      data = segment.data
      segmentPos = segment.pos
      segmentLimit = segment.limit
    }

    if (data[segmentPos] != bytes[i]) {
      return false
    }

    segmentPos++
    i++
  }

  return true
}

internal inline fun <T> Buffer.seek(
  fromIndex: Long,
  lambda: (Segment?, Long) -> T,
): T {
  var s: Segment = head ?: return lambda(null, -1L)

  if (size - fromIndex < fromIndex) {
    // We're scanning in the back half of this buffer. Find the segment starting at the back.
    var offset = size
    while (offset > fromIndex) {
      s = s.prev!!
      offset -= (s.limit - s.pos).toLong()
    }
    return lambda(s, offset)
  } else {
    // We're scanning in the front half of this buffer. Find the segment starting at the front.
    var offset = 0L
    while (true) {
      val nextOffset = offset + (s.limit - s.pos)
      if (nextOffset > fromIndex) break
      s = s.next!!
      offset = nextOffset
    }
    return lambda(s, offset)
  }
}

internal inline fun Buffer.commonReadShort(): Short {
  if (size < 2L) throw EOFException()

  val segment = head!!
  var pos = segment.pos
  val limit = segment.limit

  // If the short is split across multiple segments, delegate to readByte().
  if (limit - pos < 2) {
    val s = readByte() and 0xff shl 8 or (readByte() and 0xff)
    return s.toShort()
  }

  val data = segment.data
  val s = data[pos++] and 0xff shl 8 or (data[pos++] and 0xff)
  size -= 2L

  if (pos == limit) {
    head = segment.pop()
    SegmentPool.recycle(segment)
  } else {
    segment.pos = pos
  }

  return s.toShort()
}

internal inline fun Buffer.commonWritableSegment(minimumCapacity: Int): Segment {
  require(minimumCapacity >= 1 && minimumCapacity <= Segment.SIZE) { "unexpected capacity" }

  if (head == null) {
    val result = SegmentPool.take() // Acquire a first segment.
    head = result
    result.prev = result
    result.next = result
    return result
  }

  var tail = head!!.prev
  if (tail!!.limit + minimumCapacity > Segment.SIZE || !tail.owner) {
    tail = tail.push(SegmentPool.take()) // Append a new empty segment to fill up.
  }
  return tail
}

internal inline fun RealBufferedSource.commonSelect(options: Options): Int {
  check(!closed) { "closed" }

  while (true) {
    val index = buffer.selectPrefix(options, selectTruncated = true)
    when (index) {
      -1 -> {
        return -1
      }
      -2 -> {
        // We need to grow the buffer. Do that, then try it all again.
        if (source.read(buffer, Segment.SIZE.toLong()) == -1L) return -1
      }
      else -> {
        // We matched a full byte string: consume it and return it.
        val selectedSize = options.byteStrings[index].size
        buffer.skip(selectedSize.toLong())
        return index
      }
    }
  }
}

internal inline fun RealBufferedSource.commonIndexOf(b: Byte, fromIndex: Long, toIndex: Long): Long {
  var fromIndex = fromIndex
  check(!closed) { "closed" }
  require(fromIndex in 0L..toIndex) { "fromIndex=$fromIndex toIndex=$toIndex" }

  while (fromIndex < toIndex) {
    val result = buffer.indexOf(b, fromIndex, toIndex)
    if (result != -1L) return result

    // The byte wasn't in the buffer. Give up if we've already reached our target size or if the
    // underlying stream is exhausted.
    val lastBufferSize = buffer.size
    if (lastBufferSize >= toIndex || source.read(buffer, Segment.SIZE.toLong()) == -1L) return -1L

    // Continue the search from where we left off.
    fromIndex = maxOf(fromIndex, lastBufferSize)
  }
  return -1L
}

override fun fromJson(reader: JsonReader, customScalarAdapters: CustomScalarAdapters): T {
  val actualReader = if (buffered) {
    reader.buffer()
  } else {
    reader
  }
  actualReader.beginObject()
  try {
    val result = wrappedAdapter.fromJson(actualReader, customScalarAdapters)
    actualReader.endObject()
    return result
  } catch (e: ApolloGraphQLException) {
    // There was an error. Consume the remaining entries of the object
    while (actualReader.hasNext()) {
      actualReader.nextName()
      actualReader.skipValue()
    }
    actualReader.endObject()
    throw e
  }
}

fun argumentValue(
    name: String,
    variables: Executable.Variables,
): Optional<ApolloJsonElement> {
  val argument = arguments.firstOrNull { it.definition.name == name }
  if (argument == null) {
    // no such argument
    return Optional.Absent
  }
  if (argument.value is Optional.Absent) {
    // this argument has no value
    return Optional.Absent
  }

  val value = argument.value.getOrThrow()
  return if (value is CompiledVariable) {
    if (variables.valueMap.containsKey(value.name)) {
      Optional.present(variables.valueMap[value.name])
    } else {
      // this argument has a variable value that is absent
      // This is where we should use the argument defaultValue if any
      Optional.Absent
    }
  } else {
    Optional.present(resolveVariables(value, variables))
  }
}

@Deprecated("appendQueryParameters was not supposed to be exposed and will be removed in a future version. Use a dedicated URL parsing library instead.")
    @ApolloDeprecatedSince(ApolloDeprecatedSince.Version.v5_0_0)
    fun String.appendQueryParameters(parameters: Map<String, String>): String = buildString {
      append(this@appendQueryParameters)
      var hasQuestionMark = this@appendQueryParameters.contains("?")

      parameters.entries.forEach {
        if (hasQuestionMark) {
          append('&')
        } else {
          hasQuestionMark = true
          append('?')
        }
        append(it.key.urlEncode())
        append('=')
        append(it.value.urlEncode())
      }
    }

private fun <T> valueInternal(value: T?) = apply {
  when (val state = stack.lastOrNull()) {
    is State.Map -> {
      val name = state.name
      check(name != null)
      if (state.map.containsKey(name)) {
        // There is already a value. This happens when using fragments and operationBased codegen
        // when we have to rewind the parser
        state.map[name] = state.map[name].mergeWith(value)
      } else {
        state.map[name] = value
      }
      state.name = null
    }
    is State.List -> {
      state.list.add(value)
    }
    else -> {
      root = value
      rootSet = true
    }
  }
}

@JvmOverloads
fun <D : Operation.Data> Operation<D>.parseResponse(
    jsonReader: JsonReader,
    requestUuid: Uuid? = null,
    customScalarAdapters: CustomScalarAdapters = CustomScalarAdapters.Empty,
    deferredFragmentIdentifiers: Set<DeferredFragmentIdentifier>? = null,
): ApolloResponse<D> {
  return try {
    ResponseParser.parse(
        jsonReader,
        this,
        requestUuid,
        customScalarAdapters,
        deferredFragmentIdentifiers,
    )
  } catch (throwable: Throwable) {
    ApolloResponse.Builder(requestUuid = requestUuid ?: uuid4(), operation = this)
        .exception(exception = throwable.wrapIfNeeded())
        .isLast(true)
        .build()
  }
}

override fun visitClass(klass: KtClass) {
    val packageName = klass.containingKtFile.packageDirective?.packageNameExpression?.text

    if (packageName != null && ignorePackages.any { it.matches(packageName) }) {
        return
    }

    val isPublicOrProtected = klass.visibilityModifierTypeOrDefault().let { visibility ->
        visibility != KtTokens.INTERNAL_KEYWORD && visibility != KtTokens.PRIVATE_KEYWORD
    }
    if (isPublicOrProtected) {
        if (klass.isData()) {
            report(Finding(Entity.atName(klass), "Don't use data class"))
        }
        super.visitClass(klass)
    }
}

override fun visitParameter(parameter: KtParameter) {
    if (!parameter.isConstructor() ||
        parameter.isContainingExcludedClassOrObject(excludeClassPattern) ||
        parameter.isOverride()
    ) {
        return
    }

    val identifier = parameter.name
    if (parameter.isPrivate()) {
        visitPrivateParameter(parameter)
    } else {
        if (identifier?.matches(parameterPattern) == false) {
            report(
                Finding(
                    Entity.from(parameter),
                    message = "Constructor parameter names should match the pattern: $parameterPattern"
                )
            )
        }
    }
}

override fun visitNamedFunction(function: KtNamedFunction) {
    super.visitNamedFunction(function)

    if (function.isOverride()) {
        return
    }

    val functionName = function.nameIdentifier?.text ?: return
    if (!function.isContainingExcludedClassOrObject(excludeClassPattern) &&
        !functionName.matches(functionPattern) &&
        functionName != function.returnTypeName()
    ) {
        report(
            Finding(
                Entity.atName(function),
                message = "Function names should match the pattern: $functionPattern"
            )
        )
    }
}

override fun visitProperty(property: KtProperty) {
    if (property.isPropertyTopLevelOrInCompanion()) {
        return
    }
    if (property.isSingleUnderscore() || property.isContainingExcludedClassOrObject(excludeClassPattern)) {
        return
    }

    if (property.isOverride()) {
        return
    }

    val identifier = property.name ?: return
    if (property.isPrivate()) {
        if (!identifier.matches(privateVariablePattern)) {
            report(property, "Private variable names should match the pattern: $privateVariablePattern")
        }
    } else {
        if (!identifier.matches(variablePattern)) {
            report(property, "Variable names should match the pattern: $variablePattern")
        }
    }
}

override fun visitCallExpression(expression: KtCallExpression) {
    super.visitCallExpression(expression)

    if (visitedCallExpressions.contains(expression)) return

    if (!expression.isCallingCollectionFunPresentInSequenceReturningSequence()) return

    var counter = 1
    var nextCall = expression.nextChainedCall()
    while (nextCall != null) {
        visitedCallExpressions += nextCall
        if (!nextCall.isCallingCollectionFunPresentInSequenceReturningSequence()) {
            break
        }

        counter++
        nextCall = nextCall.nextChainedCall()
    }

    if (counter > allowedOperations) {
        val message = "${expression.text} could be .asSequence().${expression.text}"
        report(Finding(Entity.from(expression), message))
    }
}

private fun isRangeOperatorsChainCall(expression: KtElement): Boolean {
    return if (isRangeOperator(expression)) {
        true
    } else {
        when (expression) {
            is KtBinaryExpression -> {
                val receiverExpression = expression.left?.let { KtPsiUtil.safeDeparenthesize(it) } ?: return false
                isRangeOperatorsChainCall(receiverExpression)
            }

            is KtDotQualifiedExpression -> {
                val receiverExpression = KtPsiUtil.safeDeparenthesize(expression.receiverExpression)
                isRangeOperatorsChainCall(receiverExpression)
            }

            else -> {
                false
            }
        }
    }
}

override fun beginStructure(descriptor: SerialDescriptor): CompositeEncoder {
    val newMode = json.switchMode(descriptor)
    if (newMode.begin != INVALID) { // entry
        composer.print(newMode.begin)
        composer.indent()
    }

    val discriminator = polymorphicDiscriminator
    if (discriminator != null) {
        encodeTypeInfo(discriminator, polymorphicSerialName ?: descriptor.serialName)
        polymorphicDiscriminator = null
        polymorphicSerialName = null
    }

    if (mode == newMode) {
        return this
    }

    return modeReuseCache?.get(newMode.ordinal) ?: StreamingJsonEncoder(composer, json, newMode, modeReuseCache)
}

override fun answer(invocation: Invocation): Any? {
    val invocationAndMatcher =
        InternalPlatform.synchronized(answers) {
            answers
                .findLast { it.matcher.match(invocation) }
                ?.also { it.usageCount++ }
        } ?: return defaultAnswer(invocation)

    return with(invocationAndMatcher) {
        matcher.captureAnswer(invocation)

        val call =
            Call(
                invocation.method.returnType,
                invocation,
                matcher,
                invocation.fieldValueProvider,
            )

        answer.answer(call)
    }
}

fun Project.apolloTest(
    jvmTarget: Int? = null,
    block: KotlinMultiplatformExtension.() -> Unit,
) {
  configureTestAggregationProducer()
  configureJavaCompatibility(jvmTarget ?: 17)
  configureJavaAndKotlinCompilers(
      listOf(
          "kotlin.RequiresOptIn",
          "com.apollographql.apollo.annotations.ApolloExperimental",
          "com.apollographql.apollo.annotations.ApolloInternal"
      )
  )

  val kotlinExtension = extensions.findByName("kotlin") as? KotlinMultiplatformExtension
  if (kotlinExtension != null) {
    kotlinExtension.block()
    kotlinExtension.configureSourceSetGraph()
  }
  configureTesting()
}

