private class SimpleQuery<out RowType : Any>(
  private val identifier: Int,
  private val queryKeys: Array<out String>,
  private val driver: SqlDriver,
  private val fileName: String,
  private val label: String,
  private val query: String,
  mapper: (SqlCursor) -> RowType,
) : Query<RowType>(mapper) {
  override fun <R> execute(mapper: (SqlCursor) -> QueryResult<R>): QueryResult<R> {
    return driver.executeQuery(identifier, query, mapper, 0, null)
  }

  override fun toString() = "$fileName:$label"

  override fun addListener(listener: Listener) {
    driver.addListener(queryKeys = queryKeys, listener)
  }

  override fun removeListener(listener: Listener) {
    driver.removeListener(queryKeys = queryKeys, listener)
  }
}

private fun checkRequest(request: ImageRequest, interceptor: Interceptor) {
    check(request.context === initialRequest.context) {
        "Interceptor '$interceptor' cannot modify the request's context."
    }
    check(request.data !== NullRequestData) {
        "Interceptor '$interceptor' cannot set the request's data to null."
    }
    check(request.target === initialRequest.target) {
        "Interceptor '$interceptor' cannot modify the request's target."
    }
    check(request.sizeResolver === initialRequest.sizeResolver) {
        "Interceptor '$interceptor' cannot modify the request's size resolver. " +
            "Use `Interceptor.Chain.withSize` instead."
    }
}

internal fun createScope(scopeId: ScopeID, qualifier: Qualifier, source: Any? = null,scopeArchetype : TypeQualifier? = null): Scope {
    _koin.logger.debug("| (+) Scope - id:'$scopeId' q:'$qualifier'")
    if (!_scopeDefinitions.contains(qualifier)) {
        _koin.logger.debug("| Scope '$qualifier' not defined. Creating it ...")
        _scopeDefinitions.add(qualifier)
    }
    if (_scopes.contains(scopeId)) {
        throw ScopeAlreadyCreatedException("Scope with id '$scopeId' is already created")
    }
    val scope = Scope(qualifier, scopeId, _koin = _koin, scopeArchetype = scopeArchetype)
    source?.let {
        _koin.logger.debug("|- Scope source set id:'$scopeId' -> $source")
        scope.sourceValue = source
    }
    scope.linkTo(rootScope)
    _scopes[scopeId] = scope
    return scope
}

fun mockHandler(stub: Stub) =
        object : MockKInvocationHandler {
            override fun invocation(
                self: Any,
                method: Method?,
                originalCall: Callable<*>?,
                args: Array<Any?>,
            ) = stdFunctions(self, method!!, args) {
                if (method.isKotlinInline()) {
                    throw MockKException("Mocking Kotlin inline functions is not supported")
                }

                stub.handleInvocation(
                    self,
                    method.toDescription(),
                    {
                        handleOriginalCall(originalCall, method)
                    },
                    args,
                    findBackingField(self, method),
                )
            }
        }

override fun apply(target: Project) {
    with(target) {
        apply(plugin = "androidx.room")
        apply(plugin = "com.google.devtools.ksp")

        extensions.configure<KspExtension> {
            arg("room.generateKotlin", "true")
        }

        extensions.configure<RoomExtension> {
            // The schemas directory contains a schema file for each version of the Room database.
            // This is required to enable Room auto migrations.
            // See https://developer.android.com/reference/kotlin/androidx/room/AutoMigration.
            schemaDirectory("$projectDir/schemas")
        }

        dependencies {
            "implementation"(libs.findLibrary("room.runtime").get())
            "implementation"(libs.findLibrary("room.ktx").get())
            "ksp"(libs.findLibrary("room.compiler").get())
        }
    }
}

fun KotlinCommonCompilerOptions.configure(
    optIns: List<String>
) {
  freeCompilerArgs.add("-Xexpect-actual-classes")

  // Suppress "Language version 1.9 is deprecated and its support will be removed in a future version of Kotlin"
  freeCompilerArgs.add("-Xsuppress-version-warnings")

  optIns.forEach {
    freeCompilerArgs.add("-opt-in=$it")
  }

  when (this) {
    is KotlinJvmCompilerOptions -> {
      freeCompilerArgs.add("-jvm-default=no-compatibility")
    }

    is KotlinNativeCompilerOptions -> {
      freeCompilerArgs.add("-opt-in=kotlinx.cinterop.UnsafeNumber")
      freeCompilerArgs.add("-opt-in=kotlinx.cinterop.ExperimentalForeignApi")
    }

    is KotlinJsCompilerOptions -> {
      // nothing!
    }
  }
}

private fun shouldParseFragment(deferredFragmentIdentifiers: Set<DeferredFragmentIdentifier>?, path: List<Any>, label: String?): Boolean {
  if (deferredFragmentIdentifiers == null) {
    // By default, parse all deferred fragments - this is the case when parsing from the normalized cache.
    return true
  }
  val identifier = DeferredFragmentIdentifier(path, label)
  return if (deferredFragmentIdentifiers.isPending()) {
    // v0.2: parse fragments that are _not_ pending
    !deferredFragmentIdentifiers.contains(identifier)
  } else {
    // v0.1: parse fragments that have been merged
    deferredFragmentIdentifiers.contains(identifier)
  }
}

